### 5. FULL CONTENT: utils.ts (Data Transformation)

```typescript
import { PointsTransaction, TransactionType } from './Models';

type TransactionGainType = 'CARD' | 'TAG' | 'CASHBACK';
type TagSubType =
  | 'DRIVE_THRU'
  | 'PEDAGIO'
  | 'ESTACIONAMENTO'
  | 'ABASTECIMENTO'
  | 'LAVA_RAPIDO';

interface TransactionDetailField {
  label?: string;
  value?: string;
}

export const getTransactionGainType = (
  transaction: PointsTransaction,
): TransactionGainType => {
  const provider = transaction.details?.provider?.toLowerCase() || '';

  if (provider.includes('cashback')) {
    return 'CASHBACK';
  }

  const icon = transaction.icon?.toLowerCase() || '';
  const description = transaction.description?.toLowerCase() || '';

  const tagIndicators = [
    'tag',
    'pedágio',
    'pedagio',
    'estacionamento',
    'abastecimento',
    'abastece',
    'drive',
    'lava',
    'rápido',
  ];

  const isTag = tagIndicators.some(
    indicator =>
      icon.includes(indicator) ||
      description.includes(indicator) ||
      provider.includes(indicator),
  );

  return isTag ? 'TAG' : 'CARD';
};

export const getTagSubType = (
  transaction: PointsTransaction,
): TagSubType | null => {
  const description = transaction.description?.toUpperCase() || '';
  const provider = transaction.details?.provider?.toUpperCase() || '';
  const extraInfo = transaction.details?.extraInfo?.toUpperCase() || '';
  const searchText = `${description} ${provider} ${extraInfo}`;

  if (
    searchText.includes('DRIVE') ||
    searchText.includes('DRIVE-THRU') ||
    searchText.includes('DRIVE THRU')
  ) {
    return 'DRIVE_THRU';
  }
  if (searchText.includes('PEDÁGIO') || searchText.includes('PEDAGIO')) {
    return 'PEDAGIO';
  }
  if (searchText.includes('ESTACIONAMENTO')) {
    return 'ESTACIONAMENTO';
  }
  if (searchText.includes('ABASTECIMENTO') || searchText.includes('ABASTECE')) {
    return 'ABASTECIMENTO';
  }
  if (searchText.includes('LAVA') && searchText.includes('RÁPIDO')) {
    return 'LAVA_RAPIDO';
  }

  return null;
};

export const getDetailScreenTitle = (
  gainType: TransactionGainType,
  transactionType?: TransactionType,
): string => {
  if (gainType === 'CASHBACK' && transactionType === 'RESCUE') {
    return 'Detalhes de uso';
  }
  if (gainType === 'CASHBACK') {
    return 'Detalhes do Cashback';
  }
  return gainType === 'CARD' ? 'Detalhes da compra' : 'Detalhes da pontuação';
};

export const getVehicleInfo = (
  transaction: PointsTransaction,
): string | null => {
  const fields: TransactionDetailField[] = transaction.details?.fields || [];

  const marcaField = fields.find((f: TransactionDetailField) =>
    f.label?.toLowerCase().includes('marca'));
  const modeloField = fields.find((f: TransactionDetailField) =>
    f.label?.toLowerCase().includes('modelo'));
  const placaField = fields.find((f: TransactionDetailField) =>
    f.label?.toLowerCase().includes('placa'));

  const marca = marcaField?.value || '';
  const modelo = modeloField?.value || '';
  const placa = placaField?.value || '';

  if (marca && modelo && placa) {
    return `${marca} ${modelo} - ${placa}`;
  }

  if (placa) {
    return placa;
  }

  const origemField = fields.find(
    (f: TransactionDetailField) =>
      f.label?.toLowerCase().includes('origem') ||
      f.label?.toLowerCase().includes('origin'),
  );

  if (origemField?.value) {
    return origemField.value;
  }

  return null;
};

export const getPurchaseTypeLabel = (tagSubType: TagSubType | null): string => {
  if (!tagSubType) return '';

  const labels: Record<TagSubType, string> = {
    DRIVE_THRU: 'Drive Thru',
    PEDAGIO: 'Pedágio',
    ESTACIONAMENTO: 'Estacionamento',
    ABASTECIMENTO: 'Abastecimento',
    LAVA_RAPIDO: 'Lava Rápido',
  };

  return labels[tagSubType] || '';
};

export const getOrigin = (transaction: PointsTransaction): string | null => {
  const fields: TransactionDetailField[] = transaction.details?.fields || [];

  const origemField = fields.find(
    (f: TransactionDetailField) =>
      f.label?.toLowerCase().includes('origem') ||
      f.label?.toLowerCase().includes('origin'),
  );

  return origemField?.value || null;
};

export const getFormattedPointsValue = (
  amount: number,
  type: TransactionType,
): string => {
  const prefix = type === 'CREDIT' || type === 'REFUNDED' ? '+ ' : '- ';
  const label = Math.abs(amount) === 1 ? 'ponto' : 'pontos';
  return `${prefix}${Math.abs(amount).toLocaleString('pt-BR')} ${label}`;
};

export const getFormattedHighlightText = (
  date: string,
  gainType: TransactionGainType,
  moment: any,
): string => {
  const transactionDate = moment(date);
  const day = transactionDate.format('DD');
  const month = transactionDate.format('MMM').toLowerCase();
  const year = transactionDate.format('YYYY');
  const time = transactionDate.format('HH:mm');

  if (gainType === 'CASHBACK') {
    return `Pontos usados em ${day} ${month} ${year} às ${time}`;
  }

  return `Compra feita em ${day} ${month} ${year} às ${time}`;
};
```

---

### 6. Navigation Params (from src/routes/Models/index.ts)

```typescript
PointsDetail: {
  transaction: PointsTransaction;
} & OptionalAnalyticsProps;
```

The screen receives a `PointsTransaction` object directly via route params. It's the only required parameter.

---

### 7. Store Requirements

**Current Implementation:** PointsDetail does NOT use store directly. It receives data via route params.

**Related Store (for context):**
- `pointsExtractActions` slice in `src/services/store/extract.store.ts`
- Manages: `pointsExtract`, `pointsBalance`, `pointsExtractFilters`
- Used by Extract/Points screens to manage transaction lists, not PointsDetail

---

### 8. Different States/Views PointsDetail Can Show

The screen conditionally renders based on transaction data:

**Screen Titles (via `getDetailScreenTitle`):**
1. **"Detalhes da compra"** - Card purchase (gainType = 'CARD')
2. **"Detalhes da pontuação"** - Tag transaction (gainType = 'TAG')
3. **"Detalhes do Cashback"** - Cashback credit (gainType = 'CASHBACK')
4. **"Detalhes de uso"** - Cashback redemption (gainType = 'CASHBACK' + type = 'RESCUE')

**Conditional Content Sections:**
- **TagContent** - Only renders when `gainType === 'TAG'` (shows: Origin, Vehicle Info, Purchase Type)
- **Points Color** - Green (PLUS_COLOR_02) for CREDIT/REFUNDED, Red (INTENSE_COLOR_05) for others
- **Modal** - "Central de Atendimento" appears on "Relatar Problema" button press

---

### 9. Story Patterns Analysis

#### PointsScreen.stories.tsx Key Patterns:

1. **Wrapper Component Pattern** - `PointsStoryWrapper` encapsulates state and store seeding
2. **useEffect seeding** - Calls `useRootStore.getState()` to directly mutate store
3. **Conditional rendering** - isLoading, hasError, isMyOrders flags
4. **Skeleton loading** - Replaces content with `<Skeleton>` components during isLoading
5. **Error boundary** - Dedicated `ErrorState` component with icon + message
6. **Meta + argTypes** - Storybook controls for: points (number), isLoading (boolean), hasError (boolean)
7. **Navigation decorator** - Uses NavigationDecorator from `.storybook/decorators`

#### ExtractScreen.stories.tsx Key Patterns:

1. **Multi-state seeding** - Separate functions: `seedStoreLoaded()`, `seedStoreLoading()`, `seedStoreError()`, `seedStoreEmpty()`
2. **Data transformation** - Processes mock data with `processPointsExtractData()` before rendering
3. **Empty state** - `EmptyList` component with contextual message
4. **Tabs integration** - Filters transactions into "Todos" / "A expirar"
5. **Four story variants** - Loaded, Empty, Loading, Error
6. **Mock transactions** - Full PointsTransaction[] with various types (CREDIT, RESCUE, EXPIRED, REFUNDED)

---

### 10. Key Architectural Observations

**Hook Component Pattern in Action:**
- `index.tsx` = Business logic (navigation, refs, handlers, analytics)
- `view.tsx` = Pure render (no hooks except FC declaration)
- `Models/index.ts` = Type contracts
- `utils.ts` = Pure functions for data transformation

**No Local Store Usage:**
- PointsDetail is presentation-only
- All data comes via navigation params
- Parent screen (ExtractRewardProgram) manages the store

**Analytics Integration:**
- `eventScreenViewV3` - Fired once on screen focus
- `eventSelectContent` - Fired on CTA interactions
- `eventModalView` - Fired when modal opens
- Location hierarchy: monetizacao > hub_recompensas_spmais > detalhe_extrato_hub_recompensas

**DS Component Reuse:**
- DetailTransactionValue (hero card)
- BasicScreen (template)
- TagLabel, SeparatorHorizontal, CardActivity, BackDropBottom
- All from @semparar/design-system-app (no custom styling)

---

