    { id: 'screens-pointsdetail--cashback-rescue', name: 'pointsdetail-cashback-rescue' },
    { id: 'screens-pointsdetail--expired-transaction', name: 'pointsdetail-expired' },
    { id: 'screens-pointsdetail--refunded-transaction', name: 'pointsdetail-refunded' },
  ];

  for (const story of stories) {
    const url = 'http://localhost:6006/iframe.html?id=' + story.id + '&viewMode=story';
    await page.goto(url, { waitUntil: 'networkidle', timeout: 30000 });
    await page.waitForTimeout(2000);
    await page.screenshot({
      path: '.storybook/screenshots/' + story.name + '.png',
      fullPage: true,
    });
    console.log('Screenshot: ' + story.name);
  }

  await browser.close();
  console.log('Done');
})().catch(e => { console.error(e.message); process.exit(1); });
